function solve(grid, x, y, k) {
    let newGrid = grid.map(row => [...row]);
    let submatrix = [];
    for (let i = 0; i < k; i++) {
        submatrix.push(newGrid[x + i].slice(y, y + k));
    }
    submatrix = submatrix.reverse();
    for (let i = 0; i < k; i++) {
        for (let j = 0; j < k; j++) {
            newGrid[x + i][y + j] = submatrix[i][j];
        }
    }
    return newGrid;
}
